import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import axios from 'axios';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import './App.css';

// Fix for default markers in React Leaflet
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

function App() {
  const [events, setEvents] = useState([]);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [filters, setFilters] = useState({ type: '', status: '', date: '' });

  useEffect(() => {
    fetchEvents();
    const interval = setInterval(fetchEvents, 10000); // Update every 10s
    return () => clearInterval(interval);
  }, []);

  const fetchEvents = async () => {
    try {
      const res = await axios.get('http://localhost:5001/api/events');
      setEvents(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const getMarkerColor = (status) => {
    switch (status) {
      case 'Unverified': return 'grey';
      case 'Developing': return 'orange';
      case 'High Confidence': return 'red';
      default: return 'blue';
    }
  };

  const simulateReport = async () => {
    const fakeReport = {
      text: 'Explosion reported near location',
      username: 'user123',
      followerCount: 1000,
      verified: true,
      latitude: 40.7128 + (Math.random() - 0.5) * 0.1,
      longitude: -74.0060 + (Math.random() - 0.5) * 0.1,
      timestamp: new Date().toISOString()
    };
    try {
      await axios.post('http://localhost:5000/api/report', fakeReport);
      fetchEvents();
    } catch (err) {
      console.error(err);
    }
  };

  const filteredEvents = events.filter(event => {
    if (filters.type && event.type !== filters.type) return false;
    if (filters.status && event.status !== filters.status) return false;
    if (filters.date && !event.timestamp.startsWith(filters.date)) return false;
    return true;
  });

  return (
    <div className="app">
      <div className="map-container">
        <MapContainer center={[40.7128, -74.0060]} zoom={10} style={{ height: '100%', width: '100%' }}>
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          />
          {filteredEvents.map(event => (
            <Marker
              key={event._id}
              position={[event.latitude, event.longitude]}
              eventHandlers={{
                click: () => setSelectedEvent(event)
              }}
            >
              <Popup>
                <div>
                  <h3>{event.type}</h3>
                  <p>{event.description}</p>
                  <p>Credibility: {event.credibilityScore}</p>
                  <p>Reports: {event.reportCount}</p>
                  <p>Status: {event.status}</p>
                </div>
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>
      <div className="sidebar">
        <h2>Event Feed</h2>
        <div className="filters">
          <select onChange={(e) => setFilters({...filters, type: e.target.value})}>
            <option value="">All Types</option>
            <option value="drone">Drone</option>
            <option value="explosion">Explosion</option>
            <option value="missile">Missile</option>
            <option value="conflict">Conflict</option>
          </select>
          <select onChange={(e) => setFilters({...filters, status: e.target.value})}>
            <option value="">All Status</option>
            <option value="Unverified">Unverified</option>
            <option value="Developing">Developing</option>
            <option value="High Confidence">High Confidence</option>
          </select>
          <input type="date" onChange={(e) => setFilters({...filters, date: e.target.value})} />
        </div>
        <button onClick={simulateReport}>Simulate Report</button>
        {selectedEvent && (
          <div className="event-details">
            <h3>{selectedEvent.type}</h3>
            <p>{selectedEvent.description}</p>
            <p>Credibility: {selectedEvent.credibilityScore}</p>
            <p>Reports: {selectedEvent.reportCount}</p>
            <p>Status: {selectedEvent.status}</p>
            <p>Time: {new Date(selectedEvent.timestamp).toLocaleString()}</p>
          </div>
        )}
        <ul className="event-list">
          {filteredEvents.map(event => (
            <li key={event._id} onClick={() => setSelectedEvent(event)}>
              {event.type} - {event.status}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

export default App;
